    titles: [
      'IT Administrator',
      'Systems Administrator Junior',
      'Network Administrator Junior',
      'Project Coordinator IT',
      'Digital Transformation Analyst',
      'Quality Assurance Analyst IT',
      'Compliance Coordinator Technology',
      'IT Security Coordinator',
