      'Information Systems Auditor',
      'ERP Consultant Junior',
      'IT Consultant Junior',
      'Technology Consultant',
      'Security Operations Analyst',
      'Penetration Tester Junior'
    ]
  }
};

// Strategy: Group similar titles into broader queries to save API calls
// Instead of 50 individual searches, we create ~12-15 grouped queries
// and rotate which groups run each day

const queryGroups = [
  // Group 1: IT Support roles (Tier 1)
  {
    query: 'IT support help desk technician British Columbia',
    matchTitles: ['IT Support Specialist', 'Help Desk Technician', 'Technical Support Analyst', 'Desktop Support Technician'],
    tier: 1,
    priority: 'High',
    group: 'support'
  },
  // Group 2: Data Entry & Admin (Tier 1)
  {
    query: 'data entry administrative coordinator British Columbia',
    matchTitles: ['Data Entry Specialist', 'Data Entry Clerk', 'Administrative Coordinator', 'Office Administrator', 'IT Coordinator', 'Records Management Coordinator'],
    tier: 1,
    priority: 'High',
    group: 'admin'
  },
  // Group 3: Junior Developer roles (Tier 2)
  {
    query: 'junior web developer software developer British Columbia',
    matchTitles: ['Junior Web Developer', 'Junior Software Developer', 'WordPress Developer'],
    tier: 2,
    priority: 'High',
    group: 'dev-junior'
  },
  // Group 4: Data & Business Analyst (Tier 2)
  {
    query: 'data analyst business analyst junior British Columbia',
    matchTitles: ['Data Coordinator', 'Reporting Analyst', 'Business Analyst Junior', 'Data Analyst Junior', 'Operations Analyst'],
    tier: 2,
    priority: 'High',
    group: 'analyst'
  },
  // Group 5: Coordinator roles (Tier 2)
  {
    query: 'CRM coordinator document control British Columbia',
    matchTitles: ['CRM Coordinator', 'Document Control Coordinator'],
    tier: 2,
    priority: 'High',
    group: 'coordinator'
  },
  // Group 6: Frontend/Backend/Fullstack (Tier 3)
  {
    query: 'junior frontend backend full stack developer British Columbia',
    matchTitles: ['Frontend Developer Junior', 'Backend Developer Junior', 'Full Stack Developer Junior', 'Python Developer Junior'],
    tier: 3,
    priority: 'High',
    group: 'dev-mid'
  },
  // Group 7: DBA and Research (Tier 3)
  {
    query: 'database administrator research analyst junior British Columbia',
    matchTitles: ['Database Administrator Junior', 'Research Analyst', 'Digital Analyst', 'Technology Associate'],
    tier: 3,
    priority: 'High',
    group: 'research'
  },
  // Group 8: Solutions/Project Analyst (Tier 3)
  {
    query: 'solutions analyst project analyst British Columbia',
    matchTitles: ['Solutions Analyst', 'Project Analyst'],
    tier: 3,
    priority: 'High',
    group: 'solutions'
  },
  // Group 9: Sysadmin/Network (Tier 4)
  {
    query: 'IT administrator systems administrator network junior British Columbia',
    matchTitles: ['IT Administrator', 'Systems Administrator Junior', 'Network Administrator Junior', 'Project Coordinator IT'],
    tier: 4,
    priority: 'Low',
    group: 'sysadmin'
  },
  // Group 10: QA/Security (Tier 4)
  {
    query: 'QA analyst IT security coordinator cybersecurity junior British Columbia',
    matchTitles: ['Digital Transformation Analyst', 'Quality Assurance Analyst IT', 'Compliance Coordinator Technology', 'IT Security Coordinator', 'Information Security Analyst', 'Junior Cybersecurity Analyst'],
    tier: 4,
    priority: 'Low',
    group: 'security'
  },
  // Group 11: GRC/Audit (Tier 5)
  {
    query: 'GRC analyst IT auditor risk analyst junior British Columbia',
    matchTitles: ['GRC Analyst', 'Risk Analyst Technology', 'IT Auditor Junior', 'Internal Auditor IT', 'Information Systems Auditor'],
    tier: 5,
    priority: 'Low',
    group: 'audit'
  },
  // Group 12: Consulting (Tier 5)
  {
    query: 'IT consultant ERP consultant junior British Columbia',
    matchTitles: ['ERP Consultant Junior', 'IT Consultant Junior', 'Technology Consultant', 'Security Operations Analyst', 'Penetration Tester Junior'],
    tier: 5,
    priority: 'Low',
    group: 'consulting'
  }
];

// ROTATION LOGIC: Run a subset each day to stay under API limits
// Day 0: Groups 0,1,2,3,4  (Tier 1 + Tier 2 core)
// Day 1: Groups 5,6,7,8    (Tier 3 + Tier 4 part 1)
// Day 2: Groups 9,10,11    (Tier 4 part 2 + Tier 5)
// Day 3: Groups 0,1,3,5    (High priority refresh)
// Then repeats

const dayOfYear = Math.floor(
  (Date.now() - new Date(new Date().getFullYear(), 0, 0)) / 86400000
);
const rotationDay = dayOfYear % 4;

let todaysGroups;
switch (rotationDay) {
  case 0:
    todaysGroups = [0, 1, 2, 3, 4]; // Tier 1 + 2
    break;
  case 1:
    todaysGroups = [5, 6, 7, 8]; // Tier 3 + 4 start
    break;
  case 2:
    todaysGroups = [9, 10, 11]; // Tier 4 end + 5
    break;
  case 3:
    todaysGroups = [0, 1, 3, 5]; // High priority refresh
    break;
}

const queriesToRun = todaysGroups.map(i => queryGroups[i]);

// Output each query as a separate item for the next node to loop through
return queriesToRun.map(q => ({
  json: {
    query: q.query,
    matchTitles: q.matchTitles,
    tier: q.tier,
    priority: q.priority,
    group: q.group,
    location: 'British Columbia, Canada'
  }
}));

// This node sits after Read Existing Jobs in a straight line
// It pulls new jobs from Normalize and Prioritize by node name
// It pulls existing jobs from Read Existing Jobs (which is the direct input)

const existingRows = $('Ensure Sheet Data').all();

// Get new jobs from the Normalize node by name
const newJobs = $('Normalize and Prioritize').all();

// Normalize a URL for comparison
function cleanUrl(rawUrl) {
  let url = (rawUrl || '').trim().toLowerCase();
  url = url.replace(/\/+$/, '');
  url = url.split('?')[0];
  url = url.split('#')[0];
  return url;
}

// Build a set of existing URLs from the sheet
const existingURLs = new Set();
for (const row of existingRows) {
  const url = cleanUrl(row.json.URL);
  if (url) existingURLs.add(url);
}

// Filter: keep only jobs not already in the sheet
const uniqueJobs = newJobs.filter(job => {
  if (job.json._empty) return false;
  const url = cleanUrl(job.json.URL);
  return url && !existingURLs.has(url);
});

if (uniqueJobs.length === 0) {
  return [];
}

return uniqueJobs;

const queryItems = $('Build Search Queries').all();

const queryMeta = {};
for (const q of queryItems) {
  queryMeta[q.json.query] = {
    tier: q.json.tier,
    priority: q.json.priority,
    group: q.json.group,
    matchTitles: q.json.matchTitles
  };
}

const results = [];
const seenURLs = new Set();
const allItems = $input.all();

for (let idx = 0; idx < allItems.length; idx++) {
  const item = allItems[idx].json;
  const jobs = item.data || [];

  let meta = null;
  if (item.query && queryMeta[item.query]) {
    meta = queryMeta[item.query];
  }
  if (!meta && queryItems[idx]) {
    meta = {
      tier: queryItems[idx].json.tier,
      priority: queryItems[idx].json.priority,
      group: queryItems[idx].json.group,
      matchTitles: queryItems[idx].json.matchTitles
    };
  }
  if (!meta) {
    meta = { tier: 0, priority: 'Unknown', group: 'unknown', matchTitles: [] };
  }

  for (const job of jobs) {
    const url = (job.job_apply_link || job.job_google_link || job.job_url || '').trim();
    const normalizedUrl = url.toLowerCase().replace(/\/+$/, '').split('?')[0].split('#')[0];
    if (!normalizedUrl || seenURLs.has(normalizedUrl)) continue;
    seenURLs.add(normalizedUrl);

    let location = '';
    if (job.job_city && job.job_state) {
      location = `${job.job_city}, ${job.job_state}`;
    } else if (job.job_location) {
      location = job.job_location;
    }

    // BC location filter
    const bcIndicators = [
      'british columbia', 'bc', 'vancouver', 'burnaby', 'surrey',
      'richmond', 'coquitlam', 'langley', 'abbotsford', 'kelowna',
      'victoria', 'nanaimo', 'kamloops', 'new westminster',
      'north vancouver', 'west vancouver', 'delta', 'maple ridge',
      'port coquitlam', 'port moody', 'white rock', 'chilliwack',
      'penticton', 'vernon', 'courtenay', 'prince george',
      'mission', 'squamish', 'whistler', 'tri-cities', 'fulford harbour',
      'langley twp'
    ];
    const locationLower = location.toLowerCase();
    const isBCJob = bcIndicators.some(ind => locationLower.includes(ind));
    const isRemoteOrVague = locationLower.includes('remote') ||
                            locationLower.includes('canada') ||
                            locationLower === '' ||
                            locationLower.includes('hybrid');

    if (!isBCJob && !isRemoteOrVague) continue;

    // Salary
    let salary = 'Not listed';
    if (job.job_min_salary && job.job_max_salary) {
      const currency = job.job_salary_currency || 'CAD';
      salary = `$${Number(job.job_min_salary).toLocaleString()} - $${Number(job.job_max_salary).toLocaleString()} ${currency}`;
    } else if (job.job_salary) {
      salary = job.job_salary;
    }

    // Description snippet
    const desc = job.job_description || job.description || '';
    const snippet = desc.length > 300 ? desc.substring(0, 300) + '...' : desc;

    // Date posted
    let datePosted = '';
    if (job.job_posted_at_datetime_utc) {
      datePosted = job.job_posted_at_datetime_utc.split('T')[0];
    } else if (job.job_posted_at) {
      datePosted = String(job.job_posted_at);
    }

    // =============================================
    // LOCATION MISMATCH DETECTION
    // Check if the description mentions a non-BC location
    // =============================================
    const descLower = desc.toLowerCase();
    const wrongLocations = [
      { keyword: 'toronto', label: 'Toronto, ON' },
      { keyword: 'montreal', label: 'Montreal, QC' },
      { keyword: 'quebec', label: 'Quebec' },
      { keyword: 'ontario', label: 'Ontario' },
      { keyword: 'calgary', label: 'Calgary, AB' },
      { keyword: 'edmonton', label: 'Edmonton, AB' },
      { keyword: 'winnipeg', label: 'Winnipeg, MB' },
      { keyword: 'saskatoon', label: 'Saskatoon, SK' },
      { keyword: 'regina', label: 'Regina, SK' },
      { keyword: 'halifax', label: 'Halifax, NS' },
      { keyword: 'ottawa', label: 'Ottawa, ON' }
    ];

    // Check for remote/anywhere keywords that override the mismatch
    // More precise remote detection
    // "remote" alone matches too broadly (catches "remote desktop", "remote access", etc.)
    // So we use phrases that specifically indicate the JOB ITSELF is remote
    const remoteKeywords = [
      'work from home',
      'anywhere in canada',
      'fully remote',
      'remote position',
      'remote role',
      'remote opportunity',
      'location: remote',
      'remote, canada',
      'wfh',
      'work remotely'
    ];
    // Also check the title for "(Remote)" which is a strong signal
    const titleLower = (job.job_title || job.title || '').toLowerCase();
    const isRemoteJob = remoteKeywords.some(kw => descLower.includes(kw)) ||
                        titleLower.includes('remote');

    let mismatchFlag = '';
    let adjustedPriority = meta.priority;

    if (!isRemoteJob) {
      const foundWrongLocations = wrongLocations.filter(loc => descLower.includes(loc.keyword));
      if (foundWrongLocations.length > 0) {
        const wrongPlaces = foundWrongLocations.map(l => l.label).join(', ');
        mismatchFlag = `LOCATION MISMATCH: Description mentions ${wrongPlaces} but listing says BC`;
        adjustedPriority = 'Low';
      }
    }

    // Build notes
    let notes = `Search group: ${meta.group}`;
    if (mismatchFlag) {
      notes = mismatchFlag + ' | ' + notes;
    }
    if (isRemoteJob) {
      notes = 'REMOTE OK | ' + notes;
    }

    results.push({
      json: {
        Title: job.job_title || job.title || '',
        Company: job.employer_name || job.company || job.company_name || '',
        Location: location,
        URL: url,
        Source: job.job_publisher || job.source || 'Unknown',
        'Date Posted': datePosted,
        Salary: salary,
        'Description Snippet': snippet,
        'Date Scraped': new Date().toISOString().split('T')[0],
        Status: 'New',
        Priority: adjustedPriority,
        Tier: meta.tier,
        'AI Score': '',
        Notes: notes,
        'Resume Version': ''
      }
    });
  }
}

return results.length > 0 ? results : [{ json: { _empty: true } }];

const jobs = $input.all();
const count = jobs.length;
const today = new Date().toLocaleDateString('en-CA');

const highPriority = jobs.filter(j => j.json.Priority === 'High');
const lowPriority = jobs.filter(j => j.json.Priority === 'Low');

let html = `
<div style="font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, sans-serif; max-width: 650px; margin: 0 auto;">
  <p style="font-size: 15px; color: #333;">
    Hey YOUR_NAME, your job tracker found <strong>${count} new listing${count !== 1 ? 's' : ''}</strong> today (${highPriority.length} high priority, ${lowPriority.length} low priority).
  </p>
`;

if (highPriority.length > 0) {
  html += `<p style="font-size: 14px; color: #155724; font-weight: 600; margin-top: 20px;">High Priority</p>`;
  html += `<table style="width: 100%; border-collapse: collapse; font-size: 14px;">`;
  html += `<tr style="border-bottom: 2px solid #ddd; text-align: left;">
    <th style="padding: 6px 8px;">Score</th>
    <th style="padding: 6px 8px;">Title</th>
    <th style="padding: 6px 8px;">Company</th>
    <th style="padding: 6px 8px;">Location</th>
  </tr>`;

  // Sort by AI score descending (best matches first)
  highPriority.sort((a, b) => {
    const scoreA = parseInt(a.json['AI Score']) || 0;
    const scoreB = parseInt(b.json['AI Score']) || 0;
    return scoreB - scoreA;
  });

  for (const job of highPriority) {
    const d = job.json;
    const score = d['AI Score'] || 'N/A';
    const scoreColor = score >= 8 ? '#155724' : score >= 5 ? '#856404' : '#cc0000';
    html += `<tr style="border-bottom: 1px solid #eee;">
      <td style="padding: 6px 8px; font-weight: 700; color: ${scoreColor};">${score}/10</td>
      <td style="padding: 6px 8px;"><a href="${d.URL}" style="color: #1e3a5f; text-decoration: none;">${d.Title}</a></td>
      <td style="padding: 6px 8px;">${d.Company}</td>
      <td style="padding: 6px 8px;">${d.Location}</td>
    </tr>`;
  }
  html += `</table>`;
}

if (lowPriority.length > 0) {
  html += `<p style="font-size: 14px; color: #856404; font-weight: 600; margin-top: 20px;">Low Priority</p>`;
  html += `<table style="width: 100%; border-collapse: collapse; font-size: 14px;">`;
  html += `<tr style="border-bottom: 2px solid #ddd; text-align: left;">
    <th style="padding: 6px 8px;">Score</th>
    <th style="padding: 6px 8px;">Title</th>
    <th style="padding: 6px 8px;">Company</th>
    <th style="padding: 6px 8px;">Notes</th>
  </tr>`;

  lowPriority.sort((a, b) => {
    const scoreA = parseInt(a.json['AI Score']) || 0;
    const scoreB = parseInt(b.json['AI Score']) || 0;
    return scoreB - scoreA;
  });

  for (const job of lowPriority) {
    const d = job.json;
    const score = d['AI Score'] || 'N/A';
    const note = d.Notes && d.Notes.includes('LOCATION MISMATCH')
      ? d.Notes.split(' | ')[0]
      : '';
    html += `<tr style="border-bottom: 1px solid #eee;">
      <td style="padding: 6px 8px; font-weight: 700; color: #cc0000;">${score}/10</td>
      <td style="padding: 6px 8px;"><a href="${d.URL}" style="color: #1e3a5f; text-decoration: none;">${d.Title}</a></td>
      <td style="padding: 6px 8px;">${d.Company}</td>
      <td style="padding: 6px 8px; color: #cc0000; font-size: 12px;">${note}</td>
    </tr>`;
  }
  html += `</table>`;
}

html += `
  <p style="color: #999; font-size: 11px; margin-top: 24px;">
    n8n Job Tracker | ${today} | Scores by Mistral 7B via Ollama
  </p>
</div>
`;

return [{
  json: {
    emailSubject: `${count} new job${count !== 1 ? 's' : ''} found (${highPriority.length} high priority) - ${today}`,
    emailBody: html
  }
}];

const job = $json;

const prompt = `You are a job relevance scorer. Rate this job posting 1-10 for a recent BCIS graduate looking for entry-level tech roles in British Columbia, Canada.

Scoring criteria:
- 9-10: Entry-level IT support, help desk, data entry, admin coordinator role in BC. Perfect match.
- 7-8: Junior developer, junior data analyst, junior business analyst in BC. Strong match.
- 5-6: Mid-level role that a motivated junior could grow into, or a good role but not in BC (remote OK).
- 3-4: Role requires 3+ years experience, or is in a different field but tangentially related.
- 1-2: Senior role, management role, requires specialized certifications, or completely wrong location with no remote option.

Respond with ONLY a single number 1-10. No explanation, no text, just the number.

Job Title: ${job.Title}
Company: ${job.Company}
Location: ${job.Location}
Description: ${job['Description Snippet']}`;

const response = await this.helpers.httpRequest({
  method: 'POST',
  url: 'http://host.docker.internal:11434/api/generate',
  body: {
    model: 'mistral',
    prompt: prompt,
    stream: false,
    options: {
      temperature: 0.1,
      num_predict: 10
    }
  },
  json: true,
  timeout: 60000
});

const responseText = (response.response || '').trim();
const match = responseText.match(/\b(10|[1-9])\b/);
const score = match ? parseInt(match[0]) : 0;

return {
  json: {
    ...job,
    'AI Score': score
  }
};

const items = $input.all();

// If the sheet is empty (no data rows), return a dummy item
// so the flow doesn't stop here
if (!items || items.length === 0) {
  return [{ json: { URL: '' } }];
}

return items;;
